            val granted = result.all { it.value }
            val payload = JSONObject()
            payload.put("permissions", JSONObject(result.mapValues { it.value }))
            emitToWeb("permissionsResult", payload)
            if (!granted) {
                result.filterValues { !it }.keys.forEach { host.onPermissionDenied(it) }
            }
