    private val captureImageLauncher =
        host.activity().registerForActivityResult(ActivityResultContracts.TakePicture()) { success ->
            val uris = if (success && cameraImageUri != null) arrayOf(cameraImageUri!!) else emptyArray()
            filePathCallback?.onReceiveValue(uris)
            filePathCallback = null

            val payload = JSONObject()
            payload.put("success", success)
            payload.put("uri", cameraImageUri?.toString() ?: JSONObject.NULL)
            emitToWeb("cameraCaptureResult", payload)
        }

