        val sanitized = pathInAssets.trimStart('/')
        val url = "${config.appScheme}://${config.appHost}${config.assetPath}$sanitized"
        webView.loadUrl(url)
    }

    fun evaluateJavascript(script: String, callback: ValueCallback<String>? = null) {
        webView.evaluateJavascript(script, callback)
    }

    fun emitToWeb(event: String, payload: JSONObject = JSONObject()) {
        val js = """
            (function() {
              if (window.HybridNative && typeof window.HybridNative.onNativeEvent === 'function') {
                window.HybridNative.onNativeEvent(${JSONObject.quote(event)}, $payload);
              }
              window.dispatchEvent(new CustomEvent('native:$event', { detail: $payload }));
            })();
        """.trimIndent()
        webView.post { webView.evaluateJavascript(js, null) }
    }

    fun canGoBack(): Boolean = webView.canGoBack()

    fun goBack() {
        webView.goBack()
    }

    fun reload() {
        webView.reload()
    }

    fun onResume() {
